package com.agrios.platform.serviceappointment.domain;
import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="provider_availability",schema="service")
public class ProviderAvailabilityEntity { @Id private UUID id; @Column(nullable=false) private UUID tenantId; @Column(nullable=false) private UUID providerId; @Column(nullable=false) private Instant startAt; @Column(nullable=false) private Instant endAt; @Column(nullable=false) private String mode; private String locationText; @Column(nullable=false) private int capacity; @Column(nullable=false) private int bookedCount; @Column(nullable=false) private String status; @Column(nullable=false) private Instant createdAt; protected ProviderAvailabilityEntity(){} public static ProviderAvailabilityEntity create(UUID tenantId,UUID providerId,Instant start,Instant end,String mode,String location,int capacity){var v=new ProviderAvailabilityEntity();v.id=UUID.randomUUID();v.tenantId=tenantId;v.providerId=providerId;v.startAt=start;v.endAt=end;v.mode=mode;v.locationText=location;v.capacity=capacity;v.status="AVAILABLE";v.createdAt=Instant.now();return v;} public void book(){bookedCount++;} public UUID id(){return id;} public UUID providerId(){return providerId;} public Instant startAt(){return startAt;} public Instant endAt(){return endAt;} public String mode(){return mode;} public String locationText(){return locationText;} public int capacity(){return capacity;} public int bookedCount(){return bookedCount;} public String status(){return status;}}
